spec.inputArgumentsSchemaV2:
{
  "type": "object",
  "required": [
    "extractedType"
  ],
  "properties": {
    "extractedType": {
      "type": "string",
      "description": "AI-extracted complaint type (ProductQualityDefect/PackagingDefect/LabelingError/AdverseEvent/ShippingDamage/CounterfeitSuspicion/Other)."
    },
    "salesOrderData": {
      "type": "string",
      "description": "Sales-order / ERP evidence for the order (raw text or JSON from GatherEvidence)."
    },
    "transportRef": {
      "type": "string",
      "description": "Transport reference (TRX-####) from the carrier portal."
    },
    "tempMinC": {
      "type": "number",
      "description": "Minimum recorded temperature (C). 0 if no logger."
    },
    "tempMaxC": {
      "type": "number",
      "description": "Maximum recorded temperature (C). 0 if no logger."
    },
    "excursionHours": {
      "type": "number",
      "description": "Hours outside the 2-8 C cold-chain band. 0 if none/no logger."
    },
    "loggerPresent": {
      "type": "boolean",
      "description": "Whether a temperature logger reading was available."
    },
    "tempLogJson": {
      "type": "string",
      "description": "Full temperature log (text/JSON) scraped from the transport portal."
    },
    "complaintHistory": {
      "type": "string",
      "description": "Prior complaints on the same sales order / batch (text or JSON), for correlation."
    },
    "orderLines": {
      "type": "string",
      "description": "The order lines with quantity and unit price from the ERP mock data app"
    },
    "deliveryNoteData": {
      "type": "string",
      "description": "Delivery-note / goods-received evidence: what was actually delivered (delivered quantity per product/line, raw text or JSON). Empty string if not available."
    }
  }
}

spec.outputArgumentsSchemaV2:
{
  "type": "object",
  "properties": {
    "suggestedAction": {
      "type": "string",
      "description": "Single recommended action for the human to approve. Physical disposition is always BackToStock or Quarantine; Destroy is never recommended directly (it is a later decision after quarantine review).",
      "enum": [
        "BackToStock",
        "Quarantine",
        "Credit",
        "Debit",
        "None"
      ]
    },
    "financeAmount": {
      "type": "number",
      "description": "Estimated credit/debit amount if derivable from the data, else 0."
    },
    "linkedComplaints": {
      "type": "string",
      "description": "Comma-separated ids of correlated complaints on the same order/batch, or empty."
    },
    "investigationFindings": {
      "type": "string",
      "description": "Compact JSON: rootCause, gdp63 criteria (TRUE/FALSE/UNKNOWN), disposition, financeDirection, rationale."
    }
  }
}

